Add an onError handler to the toggle mutation:
onError: (err) => {
  showToast({ variant: 'error', title: language.t('dialog.mcp.toggleError'), description: err instanceof Error ? err.message : String(err) })
}

Wrap the store.set call in a try/catch:
ipcMain.handle('set-desktop-mcp-servers', (_event, servers) => {
  try {
    const store = getStore('desktop-mcp-servers')
    store.set('servers', validateAndFilterMcpServers(servers))
  } catch (e) {
    console.error('Failed to write MCP servers:', e)
    throw new Error('Failed to persist MCP server configuration')
  }
})

